partner_ids = env['res.partner'].search([('opportunity_ids', '!=', False)])
for partner_id in partner_ids:
    opportunity_ids = partner_id.opportunity_ids
    if opportunity_ids:
        opportunity_id = opportunity_ids.sorted('create_date')[-1]
        if not partner_id.user_id and opportunity_id.user_id:
            partner_id.with_context(from_server=True).write({'user_id': opportunity_id.user_id.id})
        for opportunity_id in opportunity_ids:
            if opportunity_id.user_id != partner_id.user_id and partner_id.user_id.active:
                last_user_id = opportunity_id.user_id
                opportunity_id.with_context(from_server=True).write({'user_id': partner_id.user_id.id})
                for activity_id in opportunity_id.activity_ids:
                    if activity_id.user_id != opportunity_id.user_id and activity_id.user_id == last_user_id:
                        activity_id.write({'user_id': opportunity_id.user_id.id})

for rec in records:
    if rec.active == False:
        for follower_id in env['mail.followers'].search([('partner_id.user_ids', '=', rec.id)]):
            follower_id.unlink()
        for activity_id in env['mail.activity'].search([('user_id', '=', rec.id)]):
            activity_id.unlink()
